// Strips query parameters that appear before the hash in the URL
const stripQueryParamsBeforeHash = (url) => {
  const [baseUrl, hash] = url.split('#');
  const urlWithoutQuery = baseUrl.split('?')[0];
  return hash ? `${urlWithoutQuery}#${hash}` : urlWithoutQuery;
};

</new_text>
