<new_text>router.use(function (req, next) {
  router.req = req;

  // Strip query parameters before hash in URL during initialization
  const currentUrl = window.location.href;
  const strippedUrl = stripQueryParamsBeforeHash(currentUrl);
  if (currentUrl !== strippedUrl) {
    window.history.replaceState(null, '', strippedUrl);
  }

  console.log(req);</new_text>
